example.query:
-- 1. Right join filtered by course
SELECT s.name, e.course FROM Students AS s RIGHT JOIN Enrollments AS e ON s.id = e.student_id WHERE e.course = 'DBMS';

-- 2. Right join selecting a different column pair
SELECT e.course, s.city FROM Students AS s RIGHT JOIN Enrollments AS e ON s.id = e.student_id WHERE e.course = 'Networks';

shared_table.create_sql:
CREATE TABLE Enrollments (
  id INTEGER PRIMARY KEY,
  student_id INTEGER,
  course TEXT
);
